def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    n = len(bins)
    for i in range(n):
        capacity = bins[i]
        if capacity <= 0:
            continue
        if item > capacity:
            continue
        ratio = item / capacity
        score = 0.0
        if ratio == 1:
            score = 0.0
        elif ratio > 0.9:
            score = (1 - ratio) ** 4 + 0.15
        elif 0.7 < ratio <= 0.9:
            score = np.exp(-ratio * 15) + 0.12
        elif 0.4 < ratio <= 0.7:
            score = np.sin(ratio * np.pi) / 5 + 0.07
        else:
            temp_score = 0.0
            for k in range(1, 8):
                sign = (-1) ** (k + 1)
                temp_score += sign * (ratio ** (k + 2)) / (k * 2.0)
            score = abs(temp_score) + 0.03
        neighbors_influence = 0.0
        for offset in range(1, 7):
            neighbors = []
            if i - offset >= 0:
                neighbors.append(bins[i - offset])
            if i + offset < n:
                neighbors.append(bins[i + offset])
            for neighbor_capacity in neighbors:
                if neighbor_capacity > 0:
                    diff_ratio = abs(capacity - neighbor_capacity) / max(capacity, neighbor_capacity)
                    weight = 1 / (offset ** 1.5)
                    if diff_ratio > 0.5:
                        neighbors_influence += diff_ratio * weight * 0.09
                    else:
                        neighbors_influence += diff_ratio * weight * 0.04
        capacity_factor = np.cbrt(capacity) + 0.5
        priority = score + neighbors_influence / capacity_factor
        if priority < 0:
            priority = 0
        if capacity < item * 1.2 and capacity > item:
            priority *= 0.8
        if i % 2 == 0:
            priority *= 0.95
        else:
            priority *= 1.05
        priorities[i] = priority
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        return priorities
    min_finite = np.min(finite_priorities)
    max_finite = np.max(finite_priorities)
    range_finite = max_finite - min_finite if max_finite != min_finite else 1
    for i in range(n):
        if not np.isfinite(priorities[i]):
            priorities[i] = max_finite * 6
        else:
            norm = (priorities[i] - min_finite) / range_finite
            if norm < 0.3:
                priorities[i] *= 0.7
            elif norm > 0.7:
                priorities[i] *= 1.3
    return priorities
